package bind

import (
	"net/netip"
	"testing"
)

// TestSetPeerRemoteRepointsEveryPath is the bind half of the T57 hub-failover switch:
// SetPeerRemote must repoint EVERY path's wire remote at the standby concentrator —
// OVERRIDING an already-learned remote — and update the default remote so a subsequent
// Open seeds fresh paths at the standby. This is a DELIBERATE contrast with ParseEndpoint,
// which only fills a path's remote when it is UNSET; a hub switch, by contrast, retargets
// the whole bond, so it must override. Seeding both paths with a distinct "active" remote
// first makes the assertion non-vacuous: it fails on any implementation that skips a path
// that already has a remote (the ParseEndpoint semantics).
func TestSetPeerRemoteRepointsEveryPath(t *testing.T) {
	psk := testKey(t, 0x5A)
	m, err := newMultipath(t, loopbackPaths(2), psk)
	if err != nil {
		t.Fatalf("NewMultipath: %v", err)
	}
	if _, _, err := m.Open(0); err != nil {
		t.Fatalf("Open: %v", err)
	}
	t.Cleanup(func() { _ = m.Close() })

	// Both paths have already learned/configured a remote toward the ACTIVE concentrator.
	active := netip.MustParseAddrPort("203.0.113.1:51820")
	for _, ps := range m.paths {
		ps.setRemote(active)
	}

	// Hub loss → switch the peer remote to the STANDBY concentrator.
	standby := netip.MustParseAddrPort("198.51.100.7:51820")
	m.SetPeerRemote(standby)

	for i, ps := range m.paths {
		got, ok := ps.getRemote()
		if !ok || got != standby {
			t.Fatalf("path %d remote = %v (known=%v), want standby %v (SetPeerRemote must override an existing remote)", i, got, ok, standby)
		}
	}

	// The default remote is updated too, so the next Open seeds fresh paths at the standby.
	m.mu.Lock()
	dr, has := m.defaultRemote, m.hasDefaultRemote
	m.mu.Unlock()
	if !has || dr != standby {
		t.Fatalf("defaultRemote = %v (set=%v), want %v", dr, has, standby)
	}
}

// engine applies UAPI config before binding), so the parsed address is stashed
// and also applied to any already-open path lacking its own dest_addr.
func (m *Multipath) ParseEndpoint(s string) (Endpoint, error) {
	ap, err := netip.ParseAddrPort(s)
	if err != nil {
		return nil, err
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	m.defaultRemote, m.hasDefaultRemote = ap, true
	if !m.virt.dstValid() {
		m.virt.setDst(ap)
	}
	for _, ps := range m.paths {
		if _, ok := ps.getRemote(); !ok {
			ps.setRemote(ap)
		}
	}
	return m.virt, nil
}

// SetPeerRemote repoints EVERY path's wire remote — and the default remote seeded onto
// paths without their own dest_addr — at ap, the concentrator endpoint the edge now
// sends to. It is the edge-side HUB-FAILOVER switch (T57): when every path's liveness to
// the active concentrator is DOWN (hub loss), the device advances to the next ordered
// peer endpoint (config.Peer.Endpoints) and calls this so every subsequent DATA and
// PROBE frame egresses toward the STANDBY concentrator on every path.
//
// It repoints UNIFORMLY — overriding a path's own configured dest_addr too — because a
// concentrator switch retargets the peer for the whole bond: the ordered endpoint list
// is a per-CONCENTRATOR list (one address per hub), so on failover every path must reach
// the same standby hub. (A per-path dest_addr addresses the ACTIVE concentrator's
// multi-address fronting; a hub switch supersedes it. All hubs in the ordered set share
// the peer's single WireGuard static key, so the same session identity re-handshakes
// against whichever hub is active.)
//
// It does NOT touch the engine's single virtual endpoint (invariant A1): the engine
// still sees one peer, and only the per-path fan-out BENEATH it is repointed — no
// per-packet endpoint churn reaches the engine. Fresh-session semantics (dropping the
// old hub's keypairs, no hub-to-hub state handoff) and the re-handshake initiation are
// the device's job, driven right after this call.
//
// Concurrency mirrors ParseEndpoint: it takes m.mu to publish the new default and
// repoint each path's remote (each ps.setRemote takes the path's own mutex). It is
// safe on a CLOSED bind (no paths) — the new default remote is still recorded, so the
// next Open seeds fresh paths with it.
func (m *Multipath) SetPeerRemote(ap netip.AddrPort) {
	m.mu.Lock()
	m.defaultRemote, m.hasDefaultRemote = ap, true
	for _, ps := range m.paths {
		ps.setRemote(ap)
	}
	rq := m.resequencer.Load()
	m.mu.Unlock()

	// A hub switch changes the DATA-frame SENDER identity: the standby concentrator is a
	// separate process whose outer-seq restarts near 1, far below the release point the
	// prior hub's stream advanced the shared resequencer's `next` to. Re-baseline it so the
	// standby's FIRST frame (the WG handshake response) re-anchors the release point instead
	// of being dropped as a suspect low seq — without this the tunnel never re-establishes
	// after failover (defect D32). Done OUTSIDE m.mu (the resequencer has its own mutex;
	// never nest it under m.mu). Nil on a closed bind (a resequencer is Stored per Open) —
	// the next Open seeds a fresh one whose release point re-pins to its first frame anyway.
	if rq != nil {
		rq.Rebaseline()
	}
}

// Close tears down every per-path socket and CLEARS the bind's path state so a
// subsequent Open fully rebuilds it. The amneziawg engine drives exactly this
// lifecycle — device.upLocked → BindUpdate → closeBindLocked calls Close() before
// every Open(), and a Down/Up cycles Close after Open — so Close must leave the
// bind reopenable (matching conn.StdNetBind, whose closed state is simply "no
// sockets"). Outstanding receive calls return an error as their socket closes.
func (m *Multipath) Close() error {
	m.mu.Lock()
	defer m.mu.Unlock()
	// Release the fan-in first so any reader parked on a delivery poke, and the
	// engine-facing drainer, unblock; then close the sockets so every readLoop
	// returns; then wait for them all to exit before clearing state so no reader
	// outlives this Close (and no reader touches the resequencer a later Open
	// replaces). readLoop needs no lock, so waiting under m.mu cannot deadlock.
	if m.recvClosed != nil {
		close(m.recvClosed)
	}
	err := m.closeSocketsLocked()
	m.readersWG.Wait()
	m.deliverSignal = nil
	m.recvClosed = nil
	return err
}

// closeSocketsLocked closes all path sockets and resets the bind to the unopened
// state (paths and send Codec cleared), returning the first close error. Caller
// holds m.mu. Idempotent: safe on an already-closed or never-opened bind — which
// is exactly what the engine's pre-open Close relies on.
func (m *Multipath) closeSocketsLocked() error {
	var firstErr error
	// Sockets are SHARED (one per shared path), so close them once from the shared list —
	// NOT once per (peer,path) view, which would double-close a concentrator socket.
	for _, sp := range m.shared {
		if sp.conn != nil {
			if err := sp.conn.Close(); err != nil && firstErr == nil {
				firstErr = err
			}
		}
	}
	m.shared = nil
	m.deferred = nil
	// Clear every peer's per-Open state so the next Open rebuilds it fresh (paths, send
	// Codec, FEC send/receive). The deadline-tick goroutine that reads a peer's fecSend is
	// stopped by Close (recvClosed) and joined via readersWG before state is cleared, and it
	// captured its own fecSender pointer, so niling here never races it.
	for _, p := range m.peers {
		p.paths = nil
		p.sendCodec = nil
		p.fecSend = nil
		p.fecRecv.Store(nil)
	}
	return firstErr

package bind

import (
	"testing"

	"github.com/7mind/wanbond/internal/frame"
)

// TestPeerStatePerPSKCodecAndReflector is the T84 acceptance: two peerStates built through the
// per-peer construction seam (newPeerState) from DISTINCT psks derive independent frame Codecs
// and probe Reflectors. One peer's authenticated frame is rejected by the other's Decode
// (cross-psk frames are rejected on the MAC), and each Reflector authenticates a probe ONLY
// under its own psk. This is the property the concentrator relies on: PSK is a per-peer
// attribute now, not a bond-wide singleton, so a frame minted under peer A's key cannot be
// mistaken for peer B's.
func TestPeerStatePerPSKCodecAndReflector(t *testing.T) {
	pskA := testKey(t, 0x11)
	pskB := testKey(t, 0x22)

	// The scheduler/prober collaborators are irrelevant to codec/reflector derivation, so this
	// exercises the PSK seam in isolation (nil is never dereferenced by newPeerState).
	peerA := newPeerState("peer-a", pskA, nil, nil, nil)
	peerB := newPeerState("peer-b", pskB, nil, nil, nil)

	// --- Codec: a frame encoded under peer A's psk fails peer B's Decode. ---
	encA, err := peerA.newCodec()
	if err != nil {
		t.Fatalf("peer A encode codec: %v", err)
	}
	decA, err := peerA.newCodec()
	if err != nil {
		t.Fatalf("peer A decode codec: %v", err)
	}
	decB, err := peerB.newCodec()
	if err != nil {
		t.Fatalf("peer B decode codec: %v", err)
	}

	// A PROBE frame is authenticated (MAC-covered under the peer's authKey). Peer A's own codec
	// round-trips it back to an authentic probe; peer B's codec, keyed by a DIFFERENT psk, can
	// NEVER recover it AS an authentic probe — reaching KindProbe requires both the obfuscated
	// kind byte to survive AND the MAC to verify under authKeyB, which is cryptographically
	// infeasible for a frame MAC'd under authKeyA. (Decode's exact rejection is ErrMalformed or
	// ErrAuth depending on how the random nonce garbles the kind byte under the wrong obfKey, so
	// the deterministic invariant asserted is "never accepted as a probe", not a specific error.)
	wire, err := encA.Encode(nil, frame.Probe{PathID: 0, ProbeSeq: 7, TimestampNanos: 1234, SessionID: 0xABCD})
	if err != nil {
		t.Fatalf("peer A encode: %v", err)
	}
	gotA, err := decA.Decode(wire)
	if err != nil {
		t.Fatalf("peer A must decode a frame minted under its own psk: %v", err)
	}
	if gotA.Kind() != frame.KindProbe {
		t.Fatalf("peer A decoded its own probe as kind %d, want KindProbe", gotA.Kind())
	}
	if gotB, err := decB.Decode(wire); err == nil && gotB.Kind() == frame.KindProbe {
		t.Fatalf("peer B accepted peer A's authenticated probe under a different psk: %+v", gotB)
	}

	// --- Reflector: a probe authenticates (and is reflected) ONLY under its own peer's psk. ---
	probeA, err := frame.Encode(pskA, frame.Probe{PathID: 0, ProbeSeq: 1, TimestampNanos: 99, SessionID: 0x1})
	if err != nil {
		t.Fatalf("encode probe under psk A: %v", err)
	}
	if _, err := peerA.reflector.Reflect(probeA); err != nil {
		t.Fatalf("peer A reflector must authenticate a probe under its own psk: %v", err)
	}
	// Under peer B's psk the probe never reflects: it fails the MAC, or (when the wrong obfKey
	// garbles the kind into an unauthenticated one) decodes to a non-probe the Reflector refuses.
	if _, err := peerB.reflector.Reflect(probeA); err == nil {
		t.Fatal("peer B reflector reflected a probe minted under psk A (cross-psk probe must be rejected)")
	}
}

